{
  "level": "A1–B1",
  "intro": "У цьому розділі зібрано теми, які допомагають правильно працювати з <strong>іменниками</strong>, <strong>артиклями</strong> та <strong>вираженням кількості</strong> в англійській мові.",
  "rules": [
    {
      "label": "NOUNS",
      "color": "emerald",
      "text": "<strong>Форми іменників</strong> — singular/plural, regular та irregular forms.",
      "example": "Plural Nouns, Irregular Plurals"
    },
    {
      "label": "ARTICLES",
      "color": "blue",
      "text": "<strong>Артиклі</strong> — a/an/the та нульовий артикль.",
      "example": "Articles A / An / The"
    },
    {
      "label": "QUANTITY",
      "color": "amber",
      "text": "<strong>Кількість</strong> — some, any, much, many, few, little, a lot of.",
      "example": "Some / Any, Much / Many, Few / Little"
    }
  ]
}

{
  "title": "Що входить до категорії",
  "intro": "Основні підтеми, які логічно об’єднує ця категорія:",
  "items": [
    {
      "label": "PLURAL",
      "title": "Множина іменників",
      "subtitle": "Правила -s, -es, -ies, -ves, irregular plurals, singular-only та plural-only nouns."
    },
    {
      "label": "ARTICLES",
      "title": "Артиклі",
      "subtitle": "Вживання a/an/the, zero article, типові помилки й винятки."
    },
    {
      "label": "QUANTITY",
      "title": "Кількість",
      "subtitle": "Countable vs uncountable nouns, some/any, much/many, few/little та споріднені конструкції."
    }
  ]
}

{
  "title": "Коли відкривати цей розділ",
  "sections": [
    {
      "label": "Форма слова",
      "color": "emerald",
      "description": "Коли потрібно визначити, яку форму іменника використовувати: <strong>singular</strong> чи <strong>plural</strong>.",
      "examples": [
        {
          "en": "one child / two children",
          "ua": "одна дитина / двоє дітей"
        },
        {
          "en": "a box / three boxes",
          "ua": "одна коробка / три коробки"
        }
      ]
    },
    {
      "label": "Артикль",
      "color": "blue",
      "description": "Коли треба зрозуміти, чи ставити <strong>a/an/the</strong>, чи залишати іменник без артикля.",
      "examples": [
        {
          "en": "a book",
          "ua": "будь-яка книга"
        },
        {
          "en": "the book",
          "ua": "конкретна книга"
        }
      ]
    },
    {
      "label": "Кількість",
      "color": "amber",
      "description": "Коли потрібно вибрати слово кількості: <strong>some, any, much, many, few, little</strong>.",
      "examples": [
        {
          "en": "many books",
          "ua": "багато книжок"
        },
        {
          "en": "little water",
          "ua": "мало води"
        }
      ]
    }
  ]
}

{
  "title": "Рекомендовані сторінки в цій категорії",
  "items": [
    {
      "label": "Plural Nouns — Множина іменників",
      "current": false
    },
    {
      "label": "Articles A / An / The — Артиклі",
      "current": false
    },
    {
      "label": "Countable vs Uncountable Nouns",
      "current": false
    },
    {
      "label": "Some / Any — Кількість",
      "current": false
    },
    {
      "label": "Much / Many — Кількість",
      "current": false
    },
    {
      "label": "Few / Little — Кількість",
      "current": false
    }
  ]
}
